import React, { useState, useEffect, useRef } from "react";
import { Camera, CameraResultType, CameraSource } from "@capacitor/camera";
import Tesseract from "tesseract.js";

function App() {
  const [photo, setPhoto] = useState(null);
  const [uploading, setUploading] = useState(false);
  const [recognizedText, setRecognizedText] = useState("");
  const [progress, setProgress] = useState(0);
  const canvasRef = useRef(null); // 기능: 이미지 전처리를 위한 캔버스 참조

  const takePhoto = async () => {
    try {
      const image = await Camera.getPhoto({
        quality: 100, // 최상의 화질
        allowEditing: true, // 크롭 기능을 통해 필요한 부분만 추출(정확도 향상)
        resultType: CameraResultType.Uri,
        source: CameraSource.Camera,
        saveToGallery: true,
      });
      setPhoto(image.webPath);
      setRecognizedText("");
      setProgress(0);
    } catch (err) {
      console.error("카메라 오류:", err);
    }
  };

  const deletePhoto = () => {
    setPhoto(null);
    setRecognizedText("");
    setProgress(0);
  };

  // 기능: 이미지를 흑백으로 전처리하여 OCR 정확도 향상
  const preprocessImage = (imageSrc) => {
    return new Promise((resolve) => {
      const img = new Image();
      img.src = imageSrc;
      img.onload = () => {
        const canvas = canvasRef.current;
        const ctx = canvas.getContext("2d");
        canvas.width = img.width;
        canvas.height = img.height;

        ctx.drawImage(img, 0, 0);
        const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
        const data = imageData.data;

        // 흑백 필터 적용 로직
        for (let i = 0; i < data.length; i += 4) {
          const avg = (data[i] + data[i + 1] + data[i + 2]) / 3;
          data[i] = avg; // R
          data[i + 1] = avg; // G
          data[i + 2] = avg; // B
        }
        ctx.putImageData(imageData, 0, 0);
        resolve(canvas.toDataURL("image/jpeg", 1.0));
      };
    });
  };

  const startOCR = async () => {
    if (!photo) return;
    setUploading(true);
    setProgress(0);

    try {
      // 1. 이미지 전처리 수행 (흑백 변환)
      const processedImage = await preprocessImage(photo);

      // 2. OCR 실행
      const result = await Tesseract.recognize(processedImage, "kor+eng", {
        logger: (m) => {
          if (m.status === "recognizing text") {
            setProgress(Math.round(m.progress * 100));
          }
        },
      });

      // 3. 결과 정리 (불필요한 공백 제거)
      setRecognizedText(result.data.text.trim());
    } catch (err) {
      console.error("OCR 오류:", err);
      alert("글자를 인식하는 중에 오류가 발생했습니다.");
    } finally {
      setUploading(false);
    }
  };

  const useHover = () => {
    const [hover, setHover] = useState(false);
    const onMouseEnter = () => setHover(true);
    const onMouseLeave = () => setHover(false);
    return [hover, { onMouseEnter, onMouseLeave }];
  };

  const [mainBtnHover, mainBtnHoverEvents] = useHover();
  const [ocrBtnHover, ocrBtnHoverEvents] = useHover();

  return (
    <div style={wrapperStyle}>
      <header style={headerStyle}>
        <div style={headerContentStyle}>
          <h1 style={headerTitleStyle}>🔍 고정밀 글자 인식</h1>
        </div>
      </header>

      <main style={mainStyle}>
        {/* 숨겨진 캔버스 (전처리용) */}
        <canvas ref={canvasRef} style={{ display: "none" }} />

        <div style={photoCardStyle}>
          {photo ? (
            <>
              <img src={photo} alt="Preview" style={imageStyle} />
              <button onClick={deletePhoto} style={closeButtonStyle}>
                ✕
              </button>
            </>
          ) : (
            <div style={placeholderStyle}>
              <div style={placeholderIconStyle}>📸</div>
              <p style={placeholderTextStyle}>스캔할 대상이 없어요</p>
              <p style={placeholderSubTextStyle}>
                수평을 맞춰서 촬영하면 더 정확해요
              </p>
            </div>
          )}
        </div>

        <div style={infoSectionStyle}>
          {uploading ? (
            <div style={loadingAreaStyle}>
              <div style={spinnerStyle}></div>
              <p
                style={{
                  ...statusStyle,
                  marginTop: 15,
                  fontWeight: "bold",
                  color: "#007bff",
                }}
              >
                이미지 보정 및 분석 중... {progress}%
              </p>
            </div>
          ) : recognizedText ? (
            <div style={resultContainerStyle}>
              <label style={labelStyle}>인식된 내용 (수정 가능)</label>
              <textarea
                style={textareaStyle}
                value={recognizedText}
                onChange={(e) => setRecognizedText(e.target.value)}
              />
            </div>
          ) : photo ? (
            <p style={statusStyle}>
              준비 완료! [글자 인식하기] 버튼을 눌러주세요.
            </p>
          ) : null}
        </div>
      </main>

      <footer style={footerStyle}>
        {!photo ? (
          <button
            onClick={takePhoto}
            style={{
              ...mainButtonStyle,
              ...(mainBtnHover ? mainButtonStyleHover : {}),
            }}
            {...mainBtnHoverEvents}
          >
            사진 촬영하기
          </button>
        ) : (
          <button
            onClick={startOCR}
            style={{
              ...mainButtonStyle,
              backgroundColor: recognizedText ? "#6c757d" : "#28a745",
              ...(ocrBtnHover
                ? { transform: "scale(1.02)", opacity: 0.9 }
                : {}),
            }}
            disabled={uploading}
            {...ocrBtnHoverEvents}
          >
            {uploading
              ? "분석 중..."
              : recognizedText
              ? "다시 인식하기"
              : "글자 인식하기"}
          </button>
        )}
      </footer>
    </div>
  );
}

const wrapperStyle = {
  backgroundColor: "#f4f7f6",
  minHeight: "100vh",
  display: "flex",
  flexDirection: "column",
  fontFamily: "-apple-system, sans-serif",
};
const headerStyle = {
  paddingTop: "calc(env(safe-area-inset-top, 44px) + 10px)",
  paddingBottom: "15px",
  backgroundColor: "#fff",
  display: "flex",
  justifyContent: "center",
  borderBottom: "1px solid #e0e0e0",
};
const headerContentStyle = { display: "flex", alignItems: "center" };
const headerTitleStyle = {
  fontSize: "20px",
  margin: 0,
  fontWeight: "800",
  color: "#333",
};
const mainStyle = {
  flex: 1,
  padding: "20px",
  display: "flex",
  flexDirection: "column",
  alignItems: "center",
};
const photoCardStyle = {
  width: "100%",
  maxWidth: "360px",
  aspectRatio: "1/1",
  backgroundColor: "#fff",
  borderRadius: "28px",
  boxShadow: "0 10px 25px rgba(0,0,0,0.05)",
  position: "relative",
  overflow: "hidden",
  display: "flex",
  alignItems: "center",
  justifyContent: "center",
  border: "2px dashed #ddd",
};
const imageStyle = { width: "100%", height: "100%", objectFit: "cover" };
const placeholderStyle = { textAlign: "center" };
const placeholderIconStyle = { fontSize: "50px", marginBottom: "10px" };
const placeholderTextStyle = {
  fontSize: "17px",
  fontWeight: "600",
  color: "#666",
  margin: "5px 0",
};
const placeholderSubTextStyle = { fontSize: "13px", color: "#aaa", margin: 0 };
const closeButtonStyle = {
  position: "absolute",
  top: "15px",
  right: "15px",
  width: "34px",
  height: "34px",
  borderRadius: "50%",
  backgroundColor: "rgba(0,0,0,0.4)",
  color: "#fff",
  border: "none",
  fontSize: "16px",
  zIndex: 10,
};
const infoSectionStyle = {
  width: "100%",
  maxWidth: "360px",
  marginTop: "25px",
  textAlign: "center",
};
const statusStyle = { fontSize: "15px", color: "#777", margin: 0 };
const resultContainerStyle = { textAlign: "left" };
const labelStyle = {
  fontSize: "13px",
  color: "#28a745",
  fontWeight: "bold",
  marginLeft: "5px",
};
const textareaStyle = {
  width: "100%",
  padding: "16px",
  marginTop: "8px",
  borderRadius: "14px",
  border: "2px solid #28a745",
  fontSize: "15px",
  fontWeight: "600",
  boxSizing: "border-box",
  outline: "none",
  backgroundColor: "#fff",
  minHeight: "140px",
  resize: "none",
};
const loadingAreaStyle = {
  display: "flex",
  flexDirection: "column",
  alignItems: "center",
};
const spinnerStyle = {
  width: "35px",
  height: "35px",
  border: "4px solid #f3f3f3",
  borderTop: "4px solid #007bff",
  borderRadius: "50%",
  animation: "spin 1s linear infinite",
};
const footerStyle = {
  padding: "20px 20px calc(env(safe-area-inset-bottom) + 20px)",
  backgroundColor: "#fff",
  borderTop: "1px solid #eee",
};
const mainButtonStyle = {
  width: "100%",
  padding: "18px",
  borderRadius: "18px",
  border: "none",
  backgroundColor: "#007bff",
  color: "#fff",
  fontSize: "18px",
  fontWeight: "bold",
  transition: "all 0.2s",
  boxShadow: "0 5px 15px rgba(0,123,255,0.2)",
};
const mainButtonStyleHover = {
  transform: "translateY(-2px)",
  boxShadow: "0 8px 20px rgba(0,123,255,0.3)",
};

export default App;
